```go
package main

import (
	"bufio"
	"crypto/sha1"
	"encoding/hex"
	"fmt"
	"io"
	"io/ioutil"
	"os"
	"path/filepath"
	"strconv"
	"strings"
	"time"
)

const (
	objDir   = ".minigit/objects"
	refsDir  = ".minigit/refs"
	headFile = ".minigit/HEAD"
	indexFile = ".minigit/index"
)

func main() {
	if len(os.Args) < 2 {
		die("usage: minigit <command> [<args>...]")
	}
	cmd := os.Args[1]
	switch cmd {
	case "init":
		initCmd()
	case "hash-object":
		if len(os.Args) != 3 {
			die("usage: minigit hash-object <file>")
		}
		hashObjectCmd(os.Args[2])
	case "cat-file":
		if len(os.Args) != 3 {
			die("usage: minigit cat-file <sha>")
		}
		catFileCmd(os.Args[2])
	case "write-tree":
		writeTreeCmd()
	case "read-tree":
		if len(os.Args) != 3 {
			die("usage: minigit read-tree <sha>")
		}
		readTreeCmd(os.Args[2])
	case "commit":
		if len(os.Args) < 3 {
			die("usage: minigit commit <message> [<author>]")
		}
		msg := os.Args[2]
		author := "minigit <minigit@example.com>"
		if len(os.Args) > 3 {
			author = os.Args[3]
		}
		commitCmd(msg, author)
	case "log":
		logCmd()
	case "branch":
		if len(os.Args) != 3 {
			die("usage: minigit branch <name>")
		}
		branchCmd(os.Args[2])
	case "checkout":
		if len(os.Args) != 3 {
			die("usage: minigit checkout <branch>")
		}
		checkoutCmd(os.Args[2])
	default:
		die("unknown command: " + cmd)
	}
}

func die(msg string) {
	fmt.Fprintln(os.Stderr, msg)
	os.Exit(1)
}

func initCmd() {
	if err := os.MkdirAll(objDir, 0755); err != nil {
		die(err.Error())
	}
	if err := os.MkdirAll(refsDir, 0755); err != nil {
		die(err.Error())
	}
	if err := ioutil.WriteFile(headFile, []byte("ref: refs/heads/master\n"), 0644); err != nil {
		die(err.Error())
	}
	if err := ioutil.WriteFile(indexFile, nil, 0644); err != nil {
		die(err.Error())
	}
}

func hashObjectCmd(path string) {
	data, err := ioutil.ReadFile(path)
	if err != nil {
		die(err.Error())
	}
	sha := storeObject("blob", data)
	fmt.Println(sha)
}

func catFileCmd(sha string) {
	data := getObject(sha)
	os.Stdout.Write(data)
}

func writeTreeCmd() {
	entries, err := ioutil.ReadDir(".")
	if err != nil {
		die(err.Error())
	}
	var tree []string
	for _, e := range entries {
		if strings.HasPrefix(e.Name(), ".minigit") || strings.HasPrefix(e.Name(), ".") {
			continue
		}
		if e.IsDir() {
			die("subdirs not supported")
		}
		data, err := ioutil.ReadFile(e.Name())
		if err != nil {
			die(err.Error())
		}
		sha := storeObject("blob", data)
		tree = append(tree, fmt.Sprintf("%s %s", e.Name(), sha))
	}
	treeData := []byte(strings.Join(tree, "\n"))
	sha := storeObject("tree", treeData)
	fmt.Println(sha)
}

func readTreeCmd(sha string) {
	data := getObject(sha)
	if !strings.HasPrefix(string(data), "tree ") {
		die("not a tree")
	}
	lines := strings.Split(strings.TrimSpace(string(data[5:])), "\n")
	for _, l := range lines {
		parts := strings.Split(l, " ")
		if len(parts) != 2 {
			continue
		}
		name, sha := parts[0], parts[1]
		content := getObject(sha)
		if err := ioutil.WriteFile(name, content, 0644); err != nil {
			die(err.Error())
		}
	}
}

func commitCmd(msg, author string) {
	tree := strings.TrimSpace(readStdin("write-tree"))
	parent := ""
	if head, err := ioutil.ReadFile(headFile); err == nil {
		ref := strings.TrimSpace(strings.TrimPrefix(string(head), "ref: "))
		if p, err := ioutil.ReadFile(ref); err == nil {
			parent = strings.TrimSpace(string(p))
		}
	}
	ts := time.Now().Unix()
	commit := fmt.Sprintf("tree %s\nauthor %s %d\ncommitter %s %d\n\n%s\n",
		tree, author, ts, author, ts, msg)
	if parent != "" {
		commit = fmt.Sprintf("tree %s\nparent %s\nauthor %s %d\ncommitter %s %d\n\n%s\n",
			tree, parent, author, ts, author, ts, msg)
	}
	sha := storeObject("commit", []byte(commit))
	ref := "refs/heads/master"
	if head, err := ioutil.ReadFile(headFile); err == nil {
		if strings.HasPrefix(string(head), "ref: ") {
			ref = strings.TrimSpace(strings.TrimPrefix(string(head), "ref: "))
		}
	}
	if err := os.MkdirAll(filepath.Dir(ref), 0755); err != nil {
		die(err.Error())
	}
	if err := ioutil.WriteFile(ref, []byte(sha), 0644); err != nil {
		die(err.Error())
	}
	fmt.Println(sha)
}

func logCmd() {
	ref := "refs/heads/master"
	if head, err := ioutil.ReadFile(headFile); err == nil {
		if strings.HasPrefix(string(head), "ref: ") {
			ref = strings.TrimSpace(strings.TrimPrefix(string(head), "ref: "))
		}
	}
	sha := ""
	if b, err := ioutil.ReadFile(ref); err == nil {
		sha = strings.TrimSpace(string(b))
	}
	for sha != "" {
		data := getObject(sha)
		lines := strings.Split(string(data), "\n")
		var msg string
		inMsg := false
		for _, l := range lines {
			if l == "" {
				inMsg = true
				continue
			}
			if inMsg {
				msg = l
				break
			}
		}
		fmt.Printf("commit %s\n%s\n\n", sha, msg)
		parent := ""
		for _, l := range lines {
			if strings.HasPrefix(l, "parent ") {
				parent = strings.TrimPrefix(l, "parent ")
				break
			}
		}
		sha = parent
	}
}

func branchCmd(name string) {
	ref := "refs/heads/" + name
	if _, err := os.Stat(ref); err == nil {
		die("branch exists")
	}
	parent := "refs/heads/master"
	if head, err := ioutil.ReadFile(headFile); err == nil {
		if strings.HasPrefix(string(head), "ref: ") {
			parent = strings.TrimSpace(strings.TrimPrefix(string(head), "ref: "))
		}
	}
	sha := ""
	if b, err := ioutil.ReadFile(parent); err == nil {
		sha = strings.TrimSpace(string(b))
	}
	if err := ioutil.WriteFile(ref, []byte(sha), 0644); err != nil {
		die(err.Error())
	}
}

func checkoutCmd(name string) {
	ref := "refs/heads/" + name
	if _, err := os.Stat(ref); os.IsNotExist(err) {
		die("no such branch")
	}
	if err := ioutil.WriteFile(headFile, []byte("ref: "+ref+"\n"), 0644); err != nil {
		die(err.Error())
	}
	sha := ""
	if b, err := ioutil.ReadFile(ref); err == nil {
		sha = strings.TrimSpace(string(b))
	}
	readTreeCmd(sha)
}

func storeObject(typ string, data []byte) string {
	hdr := fmt.Sprintf("%s %d", typ, len(data))
	full := append([]byte(hdr), 0)
	full = append(full, data...)
	h := sha1.Sum(full)
	sha := hex.EncodeToString(h[:])
	path := filepath.Join(objDir, sha)
	if err := ioutil.WriteFile(path, full, 0644); err != nil {
		die(err.Error())
	}
	return sha
}

func getObject(sha string) []byte {
	path := filepath.Join(objDir, sha)
	data, err := ioutil.ReadFile(path)
	if err != nil {
		die(err.Error())
	}
	i := 0
	for ; i < len(data); i++ {
		if data[i] == 0 {
			break
		}
	}
	if i == len(data) {
		die("invalid object")
	}
	return data[i+1:]
}

func readStdin(cmd string) string {
	in := bufio.NewReader(os.Stdin)
	line, _ := in.ReadString('\n')
	return strings.TrimSpace(line)
}
